import{_ as e,o as t,c as s,a3 as r}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"216. Staff Appraisal","description":"","frontmatter":{"title":"216. Staff Appraisal","eba":"Mental Health Services 2024-2028","topics":["union-matters"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/education-pd/216-staff-appraisal.md","filePath":"ebas/mental-health/management-admin/education-pd/216-staff-appraisal.md"}'),n={name:"ebas/mental-health/management-admin/education-pd/216-staff-appraisal.md"};function o(i,a,p,l,f,d){return t(),s("div",null,[...a[0]||(a[0]=[r('<h1 id="_216-staff-appraisal" tabindex="-1">216. Staff Appraisal <a class="header-anchor" href="#_216-staff-appraisal" aria-label="Permalink to &quot;216. Staff Appraisal&quot;">​</a></h1><p><strong>216.1</strong> Where a system of staff appraisal does not currently exist at a workplace, the Employer may implement a performance appraisal process and the Employees will participate in that process, provided that:</p><p><strong>(a)</strong> the Employer first consults at the local level with staff and/or their union or other representative over a framework for the staff appraisal process it is seeking to introduce</p><p><strong>(b)</strong> the staff appraisal process is not used as a disciplinary tool</p><p><strong>(c)</strong> the staff appraisal process is intended to allow genuine feedback by both the Employer and Employee; and</p><p><strong>(d)</strong> the outcomes of the review are documented and confirmed and a written copy of the outcomes in given to the Employee</p><p><strong>216.2</strong> The performance appraisal and staff development scheme for Employees classified under Part 2 of <a href="/eba/ebas/mental-health/schedules/07-management-and-administrative-officers-classifications.html">Schedule 7</a> of this Agreement is set out in <a href="/eba/ebas/mental-health/management-admin/education-pd/217-individual-performance-measures-royal-children-s.html">clause 217</a> (Individual Performance Measures).</p>',7)])])}const h=e(n,[["render",o]]);export{c as __pageData,h as default};
